var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"나 참, 이런 버려진 공장에 무슨 볼일이 있다고 우리한테 정찰을 보내?","JPN":"まったく。何の用があってこんな捨てられた工場を偵察させるの？","ENG":"Geez, what could she possibly want from this abandoned factory by sending us here on patrol?","TWN":"有沒有搞錯！這種破爛工廠會有什麼事？有必要派我們來巡邏嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"부사장님은 네가 이쪽 지리를 잘 안다고 생각했겠지. 고향이랑 가까운 곳이라며?","JPN":"副社長はお前がこっちの地理に詳しいと思ったんだろう。地元から近いんだって？","ENG":"The Vice President probably thought you were familiar with this area. It's close to where you come from, right?","TWN":"副總可能以為你很熟悉這裡的地理環境吧？你的故鄉不是離這裡很近嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"넌 지구가 고향이니까 대서양 밑바닥에 뭐가 있는지도 잘 알고 있겠네?","JPN":"あんたは地球が故郷だから大西洋の海底に何があるのかもちろん知ってるのよね？","ENG":"You're from Planet Earth. Does that mean you know what lives at the bottom of the Atlantic Ocean?","TWN":"要這麼說的話，那你的故鄉是地球，你應該也很清楚大西洋海底有些什麼吧？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어… 모래상어?","JPN":"えっと……サメか？","ENG":"Err... Sand sharks?","TWN":"應該有…大鳳梨吧？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"…말을 말자.","JPN":"はあ……聞いた私が馬鹿だったわ。","ENG":"...Deliver me!","TWN":"…當我沒問。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"내가 알고 있는 거라곤, 이곳이 내가 태어나기 전부터 이런 폐허였다는 것뿐이야.","JPN":"私が知ってるのは、私が生まれる前からここは廃墟だったってことだけ。","ENG":"What I know is that this place was ruined long before I was born.","TWN":"我對這個地方唯一的認識，就是在我出生前，這裡就已經跟廢墟一樣！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"농장 밖에 없는 시골 분위기엔 어울리지 않는 공장터지.","JPN":"農場しかないド田舎の風景には似合わない工場ね。","ENG":"A factory site in the countryside that looks out of place.","TWN":"四周圍明明都是農地，卻有一個突兀的廢工廠。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"직접 부지 안에 들어와본 건 이번이 처음이라고.","JPN":"敷地内に入ったのは今回が初めてなの。","ENG":"This is my first time actually setting foot in it.","TWN":"而且我也是第一次進到裡面來好嗎！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"이쪽도 다 살펴본 것 같은데? 침식파 검출도 안 되고, 평범한 잡동사니들 밖에 없어.","JPN":"こっちも全部調べたんだが……侵食波も検出されないし、普通のがらくたしかねえな。","ENG":"We've checked everywhere on this side. No Corruption rays. There's only ordinary-looking junk here.","TWN":"這邊好像也檢查過了吧？沒有檢測到侵蝕波，只有一堆雜物而已。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"이 냉장고라도 가져갈까? 아직 쓸만해보이는데.","JPN":"この冷蔵庫でも持って帰ろうか？　まだ使えそうに見えるぞ。","ENG":"What about we take this refrigerator with us? It looks usable.","TWN":"這個冰箱要帶走嗎？好像還能用欸？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"관심 없어. 그나저나 빨리 이 냄새나는 곳에서 철수하자.","JPN":"興味ないわ。さっさとこんな臭い所から撤退するわよ。","ENG":"Not interested. Come on, let's get out of this stinky place.","TWN":"沒興趣！還是趕快離開這個臭氣熏天的地方吧！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…제시카.","JPN":"……ジェシカ。","ENG":"...Jessica.","TWN":"…潔西卡。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"아, 오르카. 너도 폐기물 더미 그만 뒤지고 비누로 손부터…","JPN":"あ、オルカ。あんたも廃棄物の山を探るのはもうやめて、石鹸で手を洗っ……","ENG":"Ah, Orca. Stop rummaging through the waste and wash your hands—","TWN":"喂，奧爾卡！你也不要再翻那堆垃圾了，趕快把手…"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"응? 그건 뭐야? TV?","JPN":"ん？　それはなに？　テレビ？","ENG":"Hm? What's that? A TV?","TWN":"嗯？那是什麼？電視嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"오, 낡은 모델이긴 해도 상태는 제법 괜찮은데?","JPN":"おお、古いモデルではあるが状態は悪くないんじゃないか？","ENG":"Oooh, it's an old model, but looks pretty good.","TWN":"哇！雖然是舊的款式，但好像還能看欸？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이거… 계속 말을 걸고 있어.","JPN":"これが……ずっと話しかけてくるの。","ENG":"It keeps talking to me.","TWN":"它…一直在對我說話。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"응? TV가 말을 건다고?","JPN":"え？　テレビが話しかけてくる？","ENG":"Huh? The TV is talking to you?","TWN":"啥？電視跟你說話？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"네 안에 있는 오르카가 속삭이는 것처럼 말이야?","JPN":"あんたの中のオルカが囁くみたいに？","ENG":"You mean, like Orca, inside you?","TWN":"就像你裡面的奧爾卡在講悄悄話一樣嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};